var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하아, 하아…….","JPN":"はあ……はあ……","ENG":"*Huff, huff...*","TWN":"呼呼，呼呼…"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"당신 대체 뭐 하다 온 여자야? 메이드 주제에 날 이렇게 몰아세운다고?","JPN":"あんたいったい何者？　メイドのくせにあたしをここまで追いつめるなんて！","ENG":"What are you? How could a simple maid put me in a corner like this?","TWN":"你到底是誰？區區一個女僕竟然可以把我逼成這樣？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"과찬이십니다, 드라코 님. 제 혼자 힘만으로는 이렇게 쉽지 않았겠어요.","JPN":"恐縮です、ドラコ様。私一人の力だけではこうも簡単にいかなかったでしょう。","ENG":"I’m flattered, Ms. Dracasia. I wouldn’t have made it this far just by myself.","TWN":"德拉克小姐，您過獎了。單憑我一己之力是無法這麼輕易辦到的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그러니 이제 무기를 거두어 주세요. 더 이상은 무의미한 싸움에 불과합니다.","JPN":"ですので、もう武器をしまってください。これ以上は無意味な戦いに過ぎません。","ENG":"Now, please put down your weapon. This battle is meaningless.","TWN":"所以還是請您棄械投降，不要再做無謂的掙扎。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님 말씀이 맞슴다. 모네도 휴가 와서 티격태격하기 싫지 말임다.","JPN":"メイド長のいうとおりっす。モネもせっかく帰省したのに、ケンカはしたくないっす。","ENG":"Our Chief Maid is right, ma’am. Mone doesn’t want to spend her vacation bickering.","TWN":"女僕長說的沒錯，莫妮也不想放假時還打打鬧鬧的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"쳇…….","JPN":"チッ……","ENG":"Sheesh...","TWN":"嗟……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"미안하지만, 난 어떻게든 너희들을 여기서 몰아내야겠어.","JPN":"悪いけど、あたしはお前らをここから追い出したいの。","ENG":"I’m sorry, but I have to see you leave this village.","TWN":"不好意思喔，我無論如何都必須把你們趕出這裡。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"진짜 끈질기네, 쟤. 마스터만큼 독종 같아.","JPN":"しつこいな。マンションマスターレベルのしぶとさだわ。","ENG":"She really is stubborn. Just like the Mansion Master.","TWN":"她還真是固執，就跟曼森主人一樣狠毒。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"왜 그렇게까지 의뢰에 집착하죠? 이미 손해가 더 크지 않습니까?","JPN":"どうしてそこまで依頼に執着するんですか？　もうそちらが損するだけの依頼なのでは？","ENG":"Why are you so obsessed with the contract? You’ve already lost too much.","TWN":"為什麼那麼堅持要完成委託呢？現在損失的應該大過酬勞吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"시끄러!","JPN":"うるさい！","ENG":"Shut up!","TWN":"要你們管！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"나나 저 아저씨들이나 징그럽게 잘 알거든?! 여기서 죽치는 동안 의뢰를 몇 건이나 놓쳤는지!","JPN":"あたしもあのおっさんたちも、うんざりするほどわかってんだよ！　ここで足止めされて他の依頼を何件も逃してるし！","ENG":"Me and those old men know it too! We lost so many contracts while we were here!","TWN":"不管是我還是那些大叔，都很清楚這段時間，我們搞砸多少次委託！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"可是…"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"어……?","JPN":"あら……？","ENG":"Huh?","TWN":"哦…？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"시엔 씨, 갑자기 바람이 무척 세진 것 같지 않아요?","JPN":"シエンさん、急に風が強くなった気がしませんか？","ENG":"Xien, it’s getting windy all of a sudden.","TWN":"西恩，你不覺得風突然變得很大嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"응? 그렇네? 하늘은 아직 쨍쨍한데?","JPN":"おや？　確かに。空は晴れているのに。","ENG":"Huh? You’re right. But the sky looks clear.","TWN":"嗯？好像是欸？可是太陽明明還很大？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"잠깐만. 저기 바다 위에 솟아오른 거, 설마…….","JPN":"待て。あの海にわき上がったものは、まさか……","ENG":"Wait, that thing on the horizon, is that...","TWN":"你看，海面上那是什麼…"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"토…… 토네이도……?!","JPN":"ト、トルネード……！？","ENG":"A tornado?","TWN":"該不會…是龍捲風…？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};